import{_ as a,o as s,c as t,ai as n}from"./chunks/framework.C4ntERNc.js";const m=JSON.parse('{"title":"Statements","description":"","frontmatter":{"title":"Statements","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/formal-reference/statements.md","filePath":"reference-manual/formal-reference/statements.md"}'),i={name:"reference-manual/formal-reference/statements.md"};function l(o,e,r,d,c,p){return s(),t("div",null,[...e[0]||(e[0]=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/formal-reference/statements.md for this page in Markdown format</div><h1 id="statements" tabindex="-1">Statements <a class="header-anchor" href="#statements" aria-label="Permalink to “Statements”">​</a></h1><h2 id="assignment-operators" tabindex="-1">Assignment operators <a class="header-anchor" href="#assignment-operators" aria-label="Permalink to “Assignment operators”">​</a></h2><table tabindex="0"><thead><tr><th>Operator</th><th>Meaning</th><th>Aliases?</th><th>Width change allowed?</th></tr></thead><tbody><tr><td><code>=</code></td><td>Alias</td><td>yes</td><td>only with <code>=z</code>/<code>=s</code></td></tr><tr><td><code>=&gt;</code></td><td>Drive</td><td>no</td><td>only with <code>=&gt;z</code>/<code>=&gt;s</code></td></tr><tr><td><code>&lt;=</code></td><td>Receive</td><td>no</td><td>only with <code>&lt;=z</code>/<code>&lt;=s</code></td></tr></tbody></table><ul><li>Suffix <code>z</code> zero-extends the narrower side.</li><li>Suffix <code>s</code> sign-extends the narrower side.</li><li>Truncation is never implicit.</li></ul><h2 id="asynchronous-assignments" tabindex="-1">ASYNCHRONOUS assignments <a class="header-anchor" href="#asynchronous-assignments" aria-label="Permalink to “ASYNCHRONOUS assignments”">​</a></h2><ul><li>Allows alias, drive, receive, slices, and concatenation LHS.</li><li>Alias operators are forbidden inside conditional control flow.</li><li>Alias operators may not have a bare literal RHS.</li><li><code>WIRE</code> and <code>PORT</code> assignments must satisfy Exclusive Assignment Rule.</li><li>Reading a net that is undriven (all drivers are <code>z</code>) is a compile error.</li><li>Combinational loops are detected and forbidden unless only in mutually exclusive branches.</li></ul><h2 id="synchronous-assignments" tabindex="-1">SYNCHRONOUS assignments <a class="header-anchor" href="#synchronous-assignments" aria-label="Permalink to “SYNCHRONOUS assignments”">​</a></h2><ul><li>Only directional operators (<code>&lt;=</code> / <code>=&gt;</code> and modifiers) are allowed. Alias (<code>=</code>) is forbidden (<code>reg = expr;</code> is a compile error).</li><li>Registers may only be written in <code>SYNCHRONOUS</code> blocks.</li><li>Each register bit may be assigned zero or one time per execution path.</li><li>Unassigned registers hold their current value (clock gating semantics).</li><li>Sliced register writes are allowed (non-overlapping per execution path).</li><li>Concatenation decomposition on the LHS is permitted: <code>{hi, lo} &lt;= expr;</code>.</li><li>Width modifiers (<code>&lt;=z</code>, <code>&lt;=s</code>, <code>=&gt;z</code>, <code>=&gt;s</code>) are available for extension when widths differ. Redundant modifiers (equal widths) are optional but harmless.</li></ul><h2 id="conditionals-if-elif-else" tabindex="-1">Conditionals (IF / ELIF / ELSE) <a class="header-anchor" href="#conditionals-if-elif-else" aria-label="Permalink to “Conditionals (IF / ELIF / ELSE)”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>IF (&lt;expr&gt;) {</span></span>
<span class="line"><span>  &lt;stmt&gt;;</span></span>
<span class="line"><span>} ELIF (&lt;expr&gt;) {</span></span>
<span class="line"><span>  &lt;stmt&gt;;</span></span>
<span class="line"><span>} ELSE {</span></span>
<span class="line"><span>  &lt;stmt&gt;;</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li>Condition must be width-1 (nonzero = true; zero = false).</li><li>Parentheses required around condition.</li><li><code>ELIF</code> and <code>ELSE</code> are optional; zero-or-more <code>ELIF</code> blocks allowed.</li><li>Branches are mutually exclusive for PED (Exclusive Assignment Rule) analysis.</li><li>Nested blocks permitted at deeper nesting levels.</li></ul><h3 id="flow-sensitive-loop-detection" tabindex="-1">Flow-sensitive loop detection <a class="header-anchor" href="#flow-sensitive-loop-detection" aria-label="Permalink to “Flow-sensitive loop detection”">​</a></h3><p>The combinational loop detector is flow-sensitive: mutually exclusive paths cannot create cycles even if they reference the same nets.</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// Valid — no loop:</span></span>
<span class="line"><span>ASYNCHRONOUS {</span></span>
<span class="line"><span>  IF (sel) { a = b; }</span></span>
<span class="line"><span>  ELSE     { b = a; }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Invalid — unconditional loop:</span></span>
<span class="line"><span>ASYNCHRONOUS {</span></span>
<span class="line"><span>  a = b;</span></span>
<span class="line"><span>  b = a;  // ERROR</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="select-case" tabindex="-1">SELECT / CASE <a class="header-anchor" href="#select-case" aria-label="Permalink to “SELECT / CASE”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>SELECT (&lt;expr&gt;) {</span></span>
<span class="line"><span>  CASE &lt;value1&gt; { &lt;stmt&gt;; }</span></span>
<span class="line"><span>  CASE &lt;value2&gt;</span></span>
<span class="line"><span>  CASE &lt;value3&gt; { &lt;stmt&gt;; }</span></span>
<span class="line"><span>  DEFAULT { &lt;stmt&gt;; }</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li>CASE labels are integer literals or <code>CONST</code> names.</li><li><code>x</code> may appear in CASE patterns (don&#39;t-care matching); x bits do not propagate into results.</li><li>Multiple CASE labels matching the same value are a compile error.</li><li>DEFAULT is optional in SYNCHRONOUS (register holds state); recommended in ASYNCHRONOUS (prevents floating nets).</li></ul><h3 id="fall-through" tabindex="-1">Fall-through <a class="header-anchor" href="#fall-through" aria-label="Permalink to “Fall-through”">​</a></h3><ul><li><strong>Naked CASE labels</strong> (without braces) fall through to the next label or block.</li><li><strong>CASE labels with braces</strong> execute statements and do not fall through.</li></ul><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>SELECT (state) {</span></span>
<span class="line"><span>  CASE 0</span></span>
<span class="line"><span>  CASE 1 { counter = counter + 1; }  // Executes for state == 0 or 1</span></span>
<span class="line"><span>  CASE 2 { counter = 8&#39;h00; }</span></span>
<span class="line"><span>  DEFAULT { counter = 8&#39;hFF; }</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="incomplete-coverage" tabindex="-1">Incomplete coverage <a class="header-anchor" href="#incomplete-coverage" aria-label="Permalink to “Incomplete coverage”">​</a></h3><ul><li>If no CASE matches and no DEFAULT exists: <ul><li>SYNCHRONOUS: register retains current value (hold state).</li><li>ASYNCHRONOUS: net has no driver from this statement (may float if no other driver).</li></ul></li></ul><h2 id="latch-assignments" tabindex="-1">LATCH assignments <a class="header-anchor" href="#latch-assignments" aria-label="Permalink to “LATCH assignments”">​</a></h2><p>Latches are written only in ASYNCHRONOUS blocks using guarded syntax:</p><ul><li>D latch: <code>latch_name &lt;= enable : data;</code></li><li>SR latch: <code>latch_name &lt;= set : reset;</code></li></ul><p>The Exclusive Assignment Rule applies to latch assignments. Bit-slicing rules apply to latch identifiers exactly as they do to registers and wires.</p><p><strong>Power-up state:</strong> A latch has no reset mechanism and no mandatory initialization value. Its power-up state is <strong>indeterminate</strong>. The designer is responsible for ensuring the latch is driven to a known state by logic before its output is consumed at an observable sink. Reading an uninitialized latch whose value may reach an observable sink is a design error.</p><h2 id="template-application-apply" tabindex="-1">Template application (<code>@apply</code>) <a class="header-anchor" href="#template-application-apply" aria-label="Permalink to “Template application (@apply)”">​</a></h2><p>Templates are applied inside <code>ASYNCHRONOUS</code> or <code>SYNCHRONOUS</code> bodies:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@apply &lt;template_id&gt; (&lt;arg_0&gt;, &lt;arg_1&gt;, ...);</span></span>
<span class="line"><span>@apply [count] &lt;template_id&gt; (&lt;arg_0&gt;, &lt;arg_1&gt;, ...);</span></span></code></pre></div><ul><li>Argument count must match the template&#39;s parameter count.</li><li>When <code>[count]</code> is specified, the template is expanded <code>count</code> times with <code>IDX</code> substituted as a compile-time literal (0 to count-1).</li><li>After expansion, the resulting statements are subject to all normal semantic rules (Exclusive Assignment, width matching, driver determinism).</li><li>See the <a href="/jz-hdl/reference-manual/formal-reference/templates.html">Templates reference</a> for full details.</li></ul><h2 id="intrinsic-operators" tabindex="-1">Intrinsic operators <a class="header-anchor" href="#intrinsic-operators" aria-label="Permalink to “Intrinsic operators”">​</a></h2><p>JZ-HDL provides 28 intrinsic operators for common hardware operations. See the <a href="/jz-hdl/reference-manual/formal-reference/expressions-and-operators.html#intrinsic-operators">complete intrinsic operators table</a> in the Expressions and Operators reference for the full list with result widths and semantics.</p><p>Common intrinsics include: <code>uadd</code>, <code>sadd</code>, <code>usub</code>, <code>ssub</code>, <code>umul</code>, <code>smul</code>, <code>clog2</code>, <code>widthof</code>, <code>lit</code>, <code>gbit</code>, <code>sbit</code>, <code>gslice</code>, <code>sslice</code>, <code>oh2b</code>, <code>b2oh</code>, <code>prienc</code>, <code>lzc</code>, <code>abs</code>, <code>umin</code>, <code>umax</code>, <code>smin</code>, <code>smax</code>, <code>popcount</code>, <code>reverse</code>, <code>bswap</code>, <code>reduce_and</code>, <code>reduce_or</code>, <code>reduce_xor</code>.</p><p>Key notes:</p><ul><li><code>clog2</code> and <code>widthof</code> are compile-time only.</li><li><code>lit</code> is a runtime literal materializer; it is not valid where a compile-time integer is required.</li><li><code>gbit</code>/<code>gslice</code> out-of-range at runtime returns 0; <code>sbit</code>/<code>sslice</code> out-of-range returns source unchanged.</li></ul>`,37)])])}const u=a(i,[["render",l]]);export{m as __pageData,u as default};
